// Script: generar_24_pwa_base.js
// Que hace: convierte CHIQUI en una PWA instalable -- el primer paso
// necesario antes de poder pedir permiso de notificaciones push.
//
//   1) public/icon-192x192.png, icon-512x512.png,
//      icon-maskable-512x512.png, apple-touch-icon.png (ARCHIVOS NUEVOS)
//      -- iconos de la app en los tamanos que piden Android, iOS, y el
//      manifest. Generados a partir del logo compacto de CHIQUI, con
//      fondo crema de marca y margen de seguridad para que Android no
//      corte partes del dibujo al aplicar distintas formas de mascara.
//
//   2) app/manifest.ts (ARCHIVO NUEVO) -- la "ficha de identidad" de la
//      PWA: nombre, colores, iconos, y como debe comportarse al
//      instalarse (pantalla completa, sin barra de navegador). Next.js
//      lo detecta automaticamente y lo sirve en /manifest.webmanifest.
//
//   3) app/layout.tsx (REEMPLAZA el existente) -- vincula el manifest,
//      agrega las etiquetas especiales que iOS necesita para el modo
//      "agregar a inicio", y de paso corrige un resto del modo oscuro
//      original que habia quedado sin actualizar (el fondo del body y
//      el color de la barra de estado del celular, ahora en la paleta
//      clara cafe/crema en vez de los tonos oscuros viejos).
//
// Como correrlo: node generar_24_pwa_base.js
// Confirma "OK" para los 6 archivos

const fs = require('fs');
const path = require('path');

function escribirImagen(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const buffer = Buffer.from(b64, 'base64');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, buffer);
  console.log('OK: ' + filePath + ' (' + (buffer.length / 1024).toFixed(1) + ' KB)');
}

function escribirTexto(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribirImagen('public/icon-192x192.png', "");
escribirImagen('public/icon-512x512.png', "");
escribirImagen('public/icon-maskable-512x512.png', "");
escribirImagen('public/apple-touch-icon.png', "");
escribirTexto('app/manifest.ts', "");
escribirTexto('app/layout.tsx', "");
